class Person:
    def __init__(self, name: str, age: int) -> None:
        self.name: str = name
        self.age: int = age

    def introduce(self) -> str:
        return f'Mən {self.name}, {self.age} yaşım var'

person: Person = Person('Dünya', 20)
print(person.introduce())

def multiply(a: int, b: int) -> int:
